4	export type SlackThreadContext = {
5	  incomingThreadTs?: string;
6	  messageTs?: string;
7	  isThreadReply: boolean;
8	  replyToId?: string;
9	  messageThreadId?: string;
10	};
11	
12	export function resolveSlackThreadContext(params: {
13	  message: SlackMessageEvent | SlackAppMentionEvent;
14	  replyToMode: ReplyToMode;
15	}): SlackThreadContext {
16	  const incomingThreadTs = params.message.thread_ts;
17	  const eventTs = params.message.event_ts;
18	  const messageTs = params.message.ts ?? eventTs;
19	  const hasThreadTs = typeof incomingThreadTs === "string" && incomingThreadTs.length > 0;
20	  const isThreadReply =
21	    hasThreadTs && (incomingThreadTs !== messageTs || Boolean(params.message.parent_user_id));
22	  const replyToId = incomingThreadTs ?? messageTs;
23	  const messageThreadId = isThreadReply
24	    ? incomingThreadTs
25	    : params.replyToMode === "all"
26	      ? messageTs
27	      : undefined;
28	  return {
29	    incomingThreadTs,
30	    messageTs,
31	    isThreadReply,
32	    replyToId,
33	    messageThreadId,
34	  };
35	}
36	
37	/**
38	 * Resolves Slack thread targeting for replies and status indicators.
39	 *
40	 * @returns replyThreadTs - Thread timestamp for reply messages
41	 * @returns statusThreadTs - Thread timestamp for status indicators (typing, etc.)
42	 * @returns isThreadReply - true if this is a genuine user reply in a thread,
43	 *                          false if thread_ts comes from a bot status message (e.g. typing indicator)
44	 */
45	export function resolveSlackThreadTargets(params: {
46	  message: SlackMessageEvent | SlackAppMentionEvent;
47	  replyToMode: ReplyToMode;
48	}) {
49	  const ctx = resolveSlackThreadContext(params);
50	  const { incomingThreadTs, messageTs, isThreadReply } = ctx;
51	  const replyThreadTs = isThreadReply
52	    ? incomingThreadTs
53	    : params.replyToMode === "all"
54	      ? messageTs
55	      : undefined;
56	  const statusThreadTs = replyThreadTs;
57	  return { replyThreadTs, statusThreadTs, isThreadReply };
58	}
