### Step 6 — `src/client.ts`

Implement a fictional `PulseBoardClient` class. This represents the protocol
layer and has no real network code — it is a plausible stub:

```typescript
export interface PulseBoardMessage {
  messageId: string;
  senderId: string;
  senderAddress: string;
  targetId: string;         // board name or user ID
  targetKind: "board" | "direct";
  text: string;
  timestamp: number;        // epoch ms
}

export type PulseBoardMessageHandler = (msg: PulseBoardMessage) => Promise<void>;

export interface PulseBoardClientOptions {
  serverUrl: string;
  token: string;
  accountId: string;
  onMessage: PulseBoardMessageHandler;
  onError: (err: Error, context: string) => void;
  onConnect: () => void;
  onDisconnect: () => void;
}

export class PulseBoardClient {
  constructor(private opts: PulseBoardClientOptions) {}
  async connect(): Promise<void> { /* stub: establish WS/polling connection */ }
  async disconnect(): Promise<void> { /* stub: close connection */ }
  async sendDirect(userId: string, text: string): Promise<string> { /* returns messageId */ }
  async sendBoard(boardId: string, text: string): Promise<string> { /* returns messageId */ }
}
```

Keep the implementation as clearly-labeled stubs (no real HTTP calls). Each
method should throw a descriptive `Error("PulseBoard: ...")` if the client is
not connected, to make runtime behavior predictable in tests.

