1	import type { ChannelSetupAdapter } from "openclaw/plugin-sdk/channel-setup";
2	import type { OpenClawConfig } from "openclaw/plugin-sdk/config-runtime";
3	import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
4	import {
5	  hasConfiguredSecretInput,
6	  normalizeSecretInputString,
7	} from "openclaw/plugin-sdk/secret-input";
8	import {
9	  createTopLevelChannelParsedAllowFromPrompt,
10	  createTopLevelChannelDmPolicy,
11	  createStandardChannelSetupStatus,
12	  mergeAllowFromEntries,
13	  parseSetupEntriesWithParser,
14	  patchTopLevelChannelConfigSection,
15	  splitSetupEntries,
16	} from "openclaw/plugin-sdk/setup";
17	import type { ChannelSetupDmPolicy } from "openclaw/plugin-sdk/setup";
18	import type { ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
19	import { formatDocsLink } from "openclaw/plugin-sdk/setup";
20	import { DEFAULT_RELAYS } from "./default-relays.js";
21	import { getPublicKeyFromPrivate, normalizePubkey } from "./nostr-bus.js";
22	import { resolveNostrAccount } from "./types.js";
23	
24	const channel = "nostr" as const;
25	
26	const NOSTR_SETUP_HELP_LINES = [
27	  "Use a Nostr private key in nsec or 64-character hex format.",
28	  "Relay URLs are optional. Leave blank to keep the default relay set.",
29	  "Env vars supported: NOSTR_PRIVATE_KEY (default account only).",
30	  `Docs: ${formatDocsLink("/channels/nostr", "channels/nostr")}`,
31	];
32	
33	const NOSTR_ALLOW_FROM_HELP_LINES = [
34	  "Allowlist Nostr DMs by npub or hex pubkey.",
35	  "Examples:",
36	  "- npub1...",
37	  "- nostr:npub1...",
38	  "- 0123456789abcdef0123456789abcdef0123456789abcdef0123456789abcdef",
39	  "Multiple entries: comma-separated.",
40	  `Docs: ${formatDocsLink("/channels/nostr", "channels/nostr")}`,
41	];
42	
43	function parseRelayUrls(raw: string): { relays: string[]; error?: string } {
44	  const entries = splitSetupEntries(raw);
45	  const relays: string[] = [];
46	  for (const entry of entries) {
47	    try {
48	      const parsed = new URL(entry);
49	      if (parsed.protocol !== "ws:" && parsed.protocol !== "wss:") {
50	        return { relays: [], error: `Relay must use ws:// or wss:// (${entry})` };
51	      }
52	    } catch {
53	      return { relays: [], error: `Invalid relay URL: ${entry}` };
54	    }
55	    relays.push(entry);
56	  }
57	  return { relays: [...new Set(relays)] };
58	}
59	
60	function parseNostrAllowFrom(raw: string): { entries: string[]; error?: string } {
61	  return parseSetupEntriesWithParser(raw, (entry) => {
62	    const cleaned = entry.replace(/^nostr:/i, "").trim();
63	    try {
64	      return { value: normalizePubkey(cleaned) };
65	    } catch {
66	      return { error: `Invalid Nostr pubkey: ${entry}` };
67	    }
68	  });
69	}
70	
71	const promptNostrAllowFrom = createTopLevelChannelParsedAllowFromPrompt({
72	  channel,
73	  defaultAccountId: DEFAULT_ACCOUNT_ID,
74	  noteTitle: "Nostr allowlist",
75	  noteLines: NOSTR_ALLOW_FROM_HELP_LINES,
76	  message: "Nostr allowFrom",
77	  placeholder: "npub1..., 0123abcd...",
78	  parseEntries: parseNostrAllowFrom,
79	  mergeEntries: ({ existing, parsed }) => mergeAllowFromEntries(existing, parsed),
80	});
81	
82	const nostrDmPolicy: ChannelSetupDmPolicy = createTopLevelChannelDmPolicy({
83	  label: "Nostr",
84	  channel,
85	  policyKey: "channels.nostr.dmPolicy",
86	  allowFromKey: "channels.nostr.allowFrom",
87	  getCurrent: (cfg) => cfg.channels?.nostr?.dmPolicy ?? "pairing",
88	  promptAllowFrom: promptNostrAllowFrom,
89	});
90	
91	export const nostrSetupAdapter: ChannelSetupAdapter = {
92	  resolveAccountId: () => DEFAULT_ACCOUNT_ID,
93	  applyAccountName: ({ cfg, name }) =>
94	    patchTopLevelChannelConfigSection({
95	      cfg,
96	      channel,
97	      patch: name?.trim() ? { name: name.trim() } : {},
98	    }),
99	  validateInput: ({ input }) => {
100	    const typedInput = input as {
101	      useEnv?: boolean;
102	      privateKey?: string;
103	      relayUrls?: string;
104	    };
105	    if (!typedInput.useEnv) {
106	      const privateKey = typedInput.privateKey?.trim();
107	      if (!privateKey) {
108	        return "Nostr requires --private-key or --use-env.";
109	      }
110	      try {
111	        getPublicKeyFromPrivate(privateKey);
112	      } catch {
113	        return "Nostr private key must be valid nsec or 64-character hex.";
114	      }
115	    }
116	    if (typedInput.relayUrls?.trim()) {
117	      return parseRelayUrls(typedInput.relayUrls).error ?? null;
118	    }
119	    return null;
120	  },
121	  applyAccountConfig: ({ cfg, input }) => {
122	    const typedInput = input as {
123	      useEnv?: boolean;
124	      privateKey?: string;
125	      relayUrls?: string;
126	    };
127	    const relayResult = typedInput.relayUrls?.trim()
128	      ? parseRelayUrls(typedInput.relayUrls)
129	      : { relays: [] };
130	    return patchTopLevelChannelConfigSection({
131	      cfg,
132	      channel,
133	      enabled: true,
134	      clearFields: typedInput.useEnv ? ["privateKey"] : undefined,
135	      patch: {
136	        ...(typedInput.useEnv ? {} : { privateKey: typedInput.privateKey?.trim() }),
137	        ...(relayResult.relays.length > 0 ? { relays: relayResult.relays } : {}),
138	      },
139	    });
140	  },
141	};
142	
143	export const nostrSetupWizard: ChannelSetupWizard = {
144	  channel,
145	  resolveAccountIdForConfigure: () => DEFAULT_ACCOUNT_ID,
146	  resolveShouldPromptAccountIds: () => false,
147	  status: createStandardChannelSetupStatus({
148	    channelLabel: "Nostr",
149	    configuredLabel: "configured",
150	    unconfiguredLabel: "needs private key",
151	    configuredHint: "configured",
152	    unconfiguredHint: "needs private key",
153	    configuredScore: 1,
154	    unconfiguredScore: 0,
155	    includeStatusLine: true,
156	    resolveConfigured: ({ cfg }) => resolveNostrAccount({ cfg }).configured,
157	    resolveExtraStatusLines: ({ cfg }) => {
158	      const account = resolveNostrAccount({ cfg });
