/**
 * Target normalization and routing helpers for PulseBoard outbound messages.
 *
 * PulseBoard uses two target conventions:
 *   @username   — direct message to a specific user
 *   #boardname  — post to a named board (group)
 */

/**
 * Normalize a raw PulseBoard target string.
 *
 * - Strips any leading `pb:` scheme prefix.
 * - Ensures a `@` sigil for direct targets and a `#` sigil for board targets.
 * - Lowercases the result for consistency.
 * - If neither sigil is present the target is treated as a direct (@) target.
 */
export function normalizePulseBoardTarget(raw: string): string {
  const trimmed = raw.trim();
  if (!trimmed) {
    return trimmed;
  }
  // Strip optional pb: scheme (e.g. pb:@alice or pb:#general)
  const cleaned = trimmed.replace(/^pb:/i, "").trim();
  if (cleaned.startsWith("#") || cleaned.startsWith("@")) {
    return cleaned.toLowerCase();
  }
  // Default to direct message target
  return `@${cleaned.toLowerCase()}`;
}

/**
 * Returns true when the target refers to a direct message recipient.
 */
export function isPulseBoardDirectTarget(target: string): boolean {
  return target.startsWith("@");
}

/**
 * Returns true when the target refers to a board (group channel).
 */
export function isPulseBoardBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Returns true when the raw input looks like a valid PulseBoard target ID:
 * either a @username, #boardname, or pb:-prefixed variant.
 */
export function looksLikePulseBoardTargetId(input: string): boolean {
  const trimmed = input.trim();
  if (!trimmed) {
    return false;
  }
  const cleaned = trimmed.replace(/^pb:/i, "").trim();
  return cleaned.startsWith("@") || cleaned.startsWith("#");
}

/**
 * Strip the leading sigil (@/#) from a normalized PulseBoard target,
 * returning the bare username or board name.
 */
export function stripPulseBoardSigil(target: string): string {
  if (target.startsWith("@") || target.startsWith("#")) {
    return target.slice(1);
  }
  return target;
}

