import { afterEach, describe, expect, it } from "vitest";
import type { OpenClawConfig } from "../api.js";
import { pulseBoardPlugin } from "./channel.js";
import { clearPulseBoardRuntime } from "./runtime.js";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
} from "./types.js";

const TEST_SERVER_URL = "https://pb.example.com";
const TEST_TOKEN = "test-pb-token-abc123";

function createConfiguredPulseBoardCfg(
  overrides: Record<string, unknown> = {},
): { channels: { pulseboard: Record<string, unknown> } } {
  return {
    channels: {
      pulseboard: {
        serverUrl: TEST_SERVER_URL,
        token: TEST_TOKEN,
        ...overrides,
      },
    },
  };
}

function requireNormalizeTarget() {
  const normalize = pulseBoardPlugin.messaging?.normalizeTarget;
  if (!normalize) {
    throw new Error("pulseboard messaging.normalizeTarget missing");
  }
  return normalize;
}

function requireLooksLikeId() {
  const looksLikeId = pulseBoardPlugin.messaging?.targetResolver?.looksLikeId;
  if (!looksLikeId) {
    throw new Error("pulseboard messaging.targetResolver.looksLikeId missing");
  }
  return looksLikeId;
}

function requirePairingNormalizer() {
  const normalize = pulseBoardPlugin.pairing?.normalizeAllowEntry;
  if (!normalize) {
    throw new Error("pulseboard pairing.normalizeAllowEntry missing");
  }
  return normalize;
}

function requireResolveDmPolicy() {
  const resolveDmPolicy = pulseBoardPlugin.security?.resolveDmPolicy;
  if (!resolveDmPolicy) {
    throw new Error("pulseboard security.resolveDmPolicy missing");
  }
  return resolveDmPolicy;
}

describe("pulseBoardPlugin", () => {
  afterEach(() => {
    clearPulseBoardRuntime();
  });

  describe("meta", () => {
    it("has correct id", () => {
      expect(pulseBoardPlugin.id).toBe("pulseboard");
    });

    it("has required meta fields", () => {
      expect(pulseBoardPlugin.meta.label).toBe("PulseBoard");
      expect(pulseBoardPlugin.meta.docsPath).toBe("/channels/pulseboard");
      expect(pulseBoardPlugin.meta.blurb).toContain("bulletin board");
    });
  });

  describe("capabilities", () => {
    it("supports direct messages", () => {
      expect(pulseBoardPlugin.capabilities.chatTypes).toContain("direct");
    });

    it("supports group (board) chats", () => {
      expect(pulseBoardPlugin.capabilities.chatTypes).toContain("group");
    });

    it("does not support media", () => {
      expect(pulseBoardPlugin.capabilities.media).toBe(false);
    });
  });

  describe("outbound", () => {
    it("uses direct delivery mode", () => {
      expect(pulseBoardPlugin.outbound?.deliveryMode).toBe("direct");
    });

    it("has 4000-character text chunk limit", () => {
      expect(pulseBoardPlugin.outbound?.textChunkLimit).toBe(4000);
    });
  });

  describe("messaging — normalizeTarget", () => {
    it("normalizes @username target", () => {
      const normalize = requireNormalizeTarget();
      expect(normalize("@alice")).toBe("@alice");
    });

    it("normalizes #boardname target", () => {
      const normalize = requireNormalizeTarget();
      expect(normalize("#general")).toBe("#general");
    });

    it("lowercases the target", () => {
      const normalize = requireNormalizeTarget();
      expect(normalize("@Alice")).toBe("@alice");
      expect(normalize("#General")).toBe("#general");
    });

    it("strips pb: scheme prefix", () => {
      const normalize = requireNormalizeTarget();
      expect(normalize("pb:@alice")).toBe("@alice");
      expect(normalize("pb:#general")).toBe("#general");
    });

    it("defaults bare words to @ direct prefix", () => {
      const normalize = requireNormalizeTarget();
      expect(normalize("alice")).toBe("@alice");
    });

    it("trims surrounding whitespace", () => {
      const normalize = requireNormalizeTarget();
      expect(normalize("  @bob  ")).toBe("@bob");
    });
  });

  describe("messaging — looksLikeId", () => {
    it("recognizes @username as valid target", () => {
      const looksLikeId = requireLooksLikeId();
      expect(looksLikeId("@alice")).toBe(true);
    });

    it("recognizes #boardname as valid target", () => {
      const looksLikeId = requireLooksLikeId();
      expect(looksLikeId("#general")).toBe(true);
    });

    it("recognizes pb:-prefixed targets", () => {
      const looksLikeId = requireLooksLikeId();
      expect(looksLikeId("pb:@alice")).toBe(true);
      expect(looksLikeId("pb:#general")).toBe(true);
    });

    it("rejects plain words without sigil", () => {
      const looksLikeId = requireLooksLikeId();
      expect(looksLikeId("alice")).toBe(false);
    });

    it("rejects empty string", () => {
      const looksLikeId = requireLooksLikeId();
      expect(looksLikeId("")).toBe(false);
    });
  });

  describe("config adapter", () => {
    it("listAccountIds returns empty array when not configured", () => {
      const cfg = { channels: {} };
      expect(pulseBoardPlugin.config.listAccountIds(cfg)).toEqual([]);
    });

    it("listAccountIds returns default when fully configured", () => {
      const cfg = createConfiguredPulseBoardCfg();
      expect(pulseBoardPlugin.config.listAccountIds(cfg)).toContain("default");
    });

    it("listAccountIds returns empty when token is missing", () => {
      const cfg = { channels: { pulseboard: { serverUrl: TEST_SERVER_URL } } };
      expect(pulseBoardPlugin.config.listAccountIds(cfg)).toEqual([]);
    });

    it("listAccountIds returns empty when serverUrl is missing", () => {
      const cfg = { channels: { pulseboard: { token: TEST_TOKEN } } };
      expect(pulseBoardPlugin.config.listAccountIds(cfg)).toEqual([]);
    });
  });

  describe("pairing", () => {
    it("has id label for pairing", () => {
      expect(pulseBoardPlugin.pairing?.idLabel).toBe("pulseBoardUsername");
    });

    it("normalizeAllowEntry strips @ sigil", () => {
      const normalize = requirePairingNormalizer();
      expect(normalize("@alice")).toBe("alice");
    });

    it("normalizeAllowEntry lowercases entries", () => {
      const normalize = requirePairingNormalizer();
      expect(normalize("Alice")).toBe("alice");
      expect(normalize("@Alice")).toBe("alice");
    });

    it("normalizeAllowEntry preserves wildcard *", () => {
      const normalize = requirePairingNormalizer();
      expect(normalize("*")).toBe("*");
    });
  });

  describe("security", () => {
    it("defaults to pairing dm policy when not configured", () => {
      const resolveDmPolicy = requireResolveDmPolicy();
      const cfg = createConfiguredPulseBoardCfg() as unknown as OpenClawConfig;
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      const result = resolveDmPolicy({ cfg, account });
      expect(result?.policy).toBe("pairing");
    });

    it("normalizes dm allowlist entries through the dm policy adapter", () => {
      const resolveDmPolicy = requireResolveDmPolicy();
      const cfg = createConfiguredPulseBoardCfg({
        dmPolicy: "allowlist",
        allowFrom: ["@Alice", "Bob"],
      }) as unknown as OpenClawConfig;
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      const result = resolveDmPolicy({ cfg, account });
      expect(result?.policy).toBe("allowlist");
      // The normalizeEntry function should strip @ and lowercase
      expect(result?.normalizeEntry?.("@Alice")).toBe("alice");
      expect(result?.normalizeEntry?.("Bob")).toBe("bob");
    });
  });

  describe("status", () => {
    it("has default runtime for the default account", () => {
      expect(pulseBoardPlugin.status?.defaultRuntime).toMatchObject({
        accountId: "default",
        running: false,
        lastStartAt: null,
        lastStopAt: null,
        lastError: null,
      });
    });
  });
});

describe("pulseboard account helpers", () => {
  describe("listPulseBoardAccountIds", () => {
    it("returns empty array when not configured", () => {
      const cfg = { channels: {} };
      expect(listPulseBoardAccountIds(cfg)).toEqual([]);
    });

    it("returns empty array when only serverUrl is set", () => {
      const cfg = { channels: { pulseboard: { serverUrl: TEST_SERVER_URL } } };
      expect(listPulseBoardAccountIds(cfg)).toEqual([]);
    });

    it("returns empty array when only token is set", () => {
      const cfg = { channels: { pulseboard: { token: TEST_TOKEN } } };
      expect(listPulseBoardAccountIds(cfg)).toEqual([]);
    });

    it("returns ['default'] when both serverUrl and token are set", () => {
      const cfg = createConfiguredPulseBoardCfg();
      expect(listPulseBoardAccountIds(cfg)).toEqual(["default"]);
    });

    it("respects configured defaultAccount name", () => {
      const cfg = createConfiguredPulseBoardCfg({ defaultAccount: "work" });
      expect(listPulseBoardAccountIds(cfg)).toEqual(["work"]);
    });
  });

  describe("resolveDefaultPulseBoardAccountId", () => {
    it("returns 'default' when fully configured", () => {
      const cfg = createConfiguredPulseBoardCfg();
      expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("default");
    });

    it("returns 'default' when not configured", () => {
      const cfg = { channels: {} };
      expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("default");
    });

    it("returns configured defaultAccount when present", () => {
      const cfg = createConfiguredPulseBoardCfg({ defaultAccount: "work" });
      expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("work");
    });
  });

  describe("resolvePulseBoardAccount", () => {
    it("resolves configured account with all fields", () => {
      const cfg = createConfiguredPulseBoardCfg({ name: "Test Bot" });
      const account = resolvePulseBoardAccount({ cfg });

      expect(account.accountId).toBe("default");
      expect(account.name).toBe("Test Bot");
      expect(account.enabled).toBe(true);
      expect(account.configured).toBe(true);
      expect(account.serverUrl).toBe(TEST_SERVER_URL);
      expect(account.token).toBe(TEST_TOKEN);
    });

    it("resolves unconfigured account with safe defaults", () => {
      const cfg = { channels: {} };
      const account = resolvePulseBoardAccount({ cfg });

      expect(account.accountId).toBe("default");
      expect(account.enabled).toBe(true);
      expect(account.configured).toBe(false);
      expect(account.serverUrl).toBe("");
      expect(account.token).toBe("");
    });

    it("handles disabled channel", () => {
      const cfg = createConfiguredPulseBoardCfg({ enabled: false });
      const account = resolvePulseBoardAccount({ cfg });

      expect(account.enabled).toBe(false);
      expect(account.configured).toBe(true);
    });

    it("preserves dmPolicy and allowFrom in config", () => {
      const cfg = createConfiguredPulseBoardCfg({
        dmPolicy: "allowlist",
        allowFrom: ["alice", "bob"],
      });
      const account = resolvePulseBoardAccount({ cfg });

      expect(account.config.dmPolicy).toBe("allowlist");
      expect(account.config.allowFrom).toEqual(["alice", "bob"]);
    });
  });
});

